/**
 * Sync the golden-input fixtures from the IM_SVG_Maker repo into the
 * visualizer's preprocess/__tests__/fixtures directory.
 *
 * IM_SVG_Maker is the canonical owner of the fixtures + their
 * .canonical.svg files (generated by `python tools/regenerate_canonicals.py`
 * in that repo). This script copies them in so the visualizer's parity
 * tests can run without a submodule.
 *
 * Override the source path via the `IM_SVG_MAKER_PATH` env var if your
 * checkout layout differs from the default sibling-dir assumption.
 */
import { existsSync, mkdirSync, readdirSync, copyFileSync, statSync } from 'node:fs'
import { dirname, join, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const HERE = dirname(fileURLToPath(import.meta.url))
const VISUALIZER_ROOT = resolve(HERE, '..')

const DEFAULT_IM_SVG_MAKER = resolve(
  VISUALIZER_ROOT,
  '..',
  'Independent_Study',
  'Assembly_docs',
  'IM_SVG_Maker'
)
const sourceRoot = process.env.IM_SVG_MAKER_PATH
  ? resolve(process.env.IM_SVG_MAKER_PATH)
  : DEFAULT_IM_SVG_MAKER

const sourceDir = join(sourceRoot, 'tests', 'fixtures')
const destDir = join(VISUALIZER_ROOT, 'src', 'preprocess', '__tests__', 'fixtures')

if (!existsSync(sourceDir)) {
  console.error(`source fixtures dir not found: ${sourceDir}`)
  console.error('set IM_SVG_MAKER_PATH if your IM_SVG_Maker checkout lives elsewhere.')
  process.exit(1)
}

mkdirSync(destDir, { recursive: true })

let n = 0
for (const name of readdirSync(sourceDir)) {
  const src = join(sourceDir, name)
  if (!statSync(src).isFile()) continue
  const dst = join(destDir, name)
  copyFileSync(src, dst)
  n++
}

console.log(`synced ${n} fixture file(s) from ${sourceDir}`)
console.log(`  -> ${destDir}`)
